#include <stdio.h>

int main(void) {
    unsigned n;
    if (scanf("%u", &n) != 1 || n > 100000u) return 1;
    unsigned long long sum = 0;
    for (unsigned i = 1; i <= n; ++i) sum += i;
    printf("%llu\n", sum);
    return 0;
}
